    putListenProgress: {
        parameters: {
            query?: never;
            header?: never;
            path: {
                bookId: string;
            };
            cookie?: never;
        };
        requestBody: {
            content: {
                "application/json": {
                    chapterId: number;
                    currentSec: number;
                    /**
                     * @description Plan 53 — per-book playback rate
                     *     (`HTMLMediaElement.playbackRate`). Optional; absent on
                     *     pre-plan-53 records. Server validates 0.25 <= rate <= 4.0
                     *     so a malformed PUT can't poison the on-disk JSON.
                     */
                    playbackRate?: number;
                    /**
                     * @description Plan 53 — user-placed bookmarks. Optional; absent on
                     *     pre-plan-53 records. Each marker carries a label + kind
                     *     so the listen-view sidebar can group "general notes"
                     *     from "re-record" flags.
                     */
                    markers?: components["schemas"]["ListenMarker"][];
                    /**
                     * Format: date-time
                     * @description srv-34 (plan 188) — optional client wall-clock time the
                     *     user actually listened. When present it stamps
                     *     `updatedAt` instead of receive-time and gates a guarded
                     *     compare-and-set (the write is rejected if not strictly
                     *     newer than the stored record). Lets an offline client
                     *     (the Android companion) flush in-car progress on
                     *     reconnect without clobbering a newer position made
                     *     elsewhere. Rejected (400) if non-date or absurdly future.
                     */
                    listenedAt?: string;
                };
            };
        };
        responses: {
            /** @description The saved record (or, on a guard-rejected stale write, the existing newer record), with updatedAt = the client listenedAt when supplied */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["ListenProgress"];
                };
            };
            /** @description Body missing chapterId or currentSec */
            400: {
                headers: {
                    [name: string]: unknown;
                };
                content?: never;
            };
            /** @description Book not found */
            404: {
                headers: {
                    [name: string]: unknown;
                };
                content?: never;
            };
        };
    };
